CREATE TYPE "FriendshipStatus" AS ENUM ('PENDING','ACCEPTED','REJECTED','BLOCKED','CANCELED');
CREATE TYPE "ChallengeCategoryStatus" AS ENUM ('ACTIVE','INACTIVE');
CREATE TYPE "ChallengeType" AS ENUM ('MOST_ATTENDANCES','FIRST_TO_TARGET','REACH_TARGET','STREAK');
CREATE TYPE "ChallengeStatus" AS ENUM ('PENDING','REJECTED','ACTIVE','COMPLETED','CANCELED','EXPIRED');
CREATE TYPE "ChallengeResult" AS ENUM ('PENDING','WIN','LOSS','DRAW','CANCELED');
CREATE TABLE "friendships" ("id" UUID PRIMARY KEY,"requester_id" UUID NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,"addressee_id" UUID NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,"status" "FriendshipStatus" NOT NULL DEFAULT 'PENDING',"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "friendships_not_self" CHECK ("requester_id"<>"addressee_id"),CONSTRAINT "friendships_requester_id_addressee_id_key" UNIQUE("requester_id","addressee_id"));
CREATE INDEX "friendships_addressee_id_status_idx" ON "friendships"("addressee_id","status");
CREATE TABLE "challenge_categories" ("id" UUID PRIMARY KEY,"name" VARCHAR(120) NOT NULL,"slug" VARCHAR(120) NOT NULL UNIQUE,"description" VARCHAR(500) NOT NULL,"type" "ChallengeType" NOT NULL,"status" "ChallengeCategoryStatus" NOT NULL DEFAULT 'ACTIVE',"duration_days" INTEGER NOT NULL,"target_attendances" INTEGER NOT NULL,"points_per_attendance" INTEGER NOT NULL DEFAULT 1,"completion_bonus" INTEGER NOT NULL DEFAULT 0,"winner_bonus" INTEGER NOT NULL DEFAULT 0,"icon" VARCHAR(50) NOT NULL DEFAULT 'flame',"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "challenge_categories_positive_values" CHECK ("duration_days">0 AND "target_attendances">0 AND "points_per_attendance">=0 AND "completion_bonus">=0 AND "winner_bonus">=0));
CREATE TABLE "challenges" ("id" UUID PRIMARY KEY,"category_id" UUID NOT NULL REFERENCES "challenge_categories"("id"),"creator_id" UUID NOT NULL REFERENCES "users"("id"),"status" "ChallengeStatus" NOT NULL DEFAULT 'PENDING',"message" VARCHAR(300),"starts_at" TIMESTAMP(3) NOT NULL,"ends_at" TIMESTAMP(3) NOT NULL,"accepted_at" TIMESTAMP(3),"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "challenges_valid_period" CHECK ("ends_at">"starts_at"));
CREATE INDEX "challenges_status_starts_at_ends_at_idx" ON "challenges"("status","starts_at","ends_at");
CREATE TABLE "challenge_participants" ("id" UUID PRIMARY KEY,"challenge_id" UUID NOT NULL REFERENCES "challenges"("id") ON DELETE CASCADE,"user_id" UUID NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,"score" INTEGER NOT NULL DEFAULT 0,"result" "ChallengeResult" NOT NULL DEFAULT 'PENDING',"accepted_at" TIMESTAMP(3),"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "challenge_participants_nonnegative_score" CHECK ("score">=0),CONSTRAINT "challenge_participants_challenge_id_user_id_key" UNIQUE("challenge_id","user_id"));
CREATE INDEX "challenge_participants_user_id_idx" ON "challenge_participants"("user_id");
CREATE TABLE "challenge_score_events" ("id" UUID PRIMARY KEY,"challenge_id" UUID NOT NULL REFERENCES "challenges"("id") ON DELETE CASCADE,"user_id" UUID NOT NULL REFERENCES "users"("id") ON DELETE CASCADE,"attendance_id" UUID NOT NULL REFERENCES "attendances"("id") ON DELETE CASCADE,"points" INTEGER NOT NULL,"idempotency_key" VARCHAR(180) NOT NULL UNIQUE,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "challenge_score_events_positive_points" CHECK ("points">0),CONSTRAINT "challenge_score_events_challenge_id_user_id_attendance_id_key" UNIQUE("challenge_id","user_id","attendance_id"));
CREATE INDEX "challenge_score_events_challenge_id_user_id_idx" ON "challenge_score_events"("challenge_id","user_id");
